/**
 * Unit tests for post-compact-recovery lifecycle hook
 * Issue #1236: Token budget carry-forward across PostCompact boundary
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { postCompactRecovery } from '../../lifecycle/post-compact-recovery.js';
import { existsSync, readFileSync } from 'node:fs';
import { outputWithContext } from '../../lib/common.js';
import type { HookInput } from '../../types.js';

function createInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'PostCompact',
    tool_name: 'PostCompact',
    session_id: 'test-session-123',
    tool_input: {},
    ...overrides,
  };
}

function mockStateFile(state: Record<string, unknown>): void {
  vi.mocked(existsSync).mockReturnValue(true);
  vi.mocked(readFileSync).mockReturnValue(JSON.stringify(state));
}

describe('lifecycle/post-compact-recovery', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('guard clauses', () => {
    test('returns silent when no state file exists', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      const result = postCompactRecovery(createInput());
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('returns silent when state has no preservedContext', () => {
      mockStateFile({ compactionCount: 1 });
      const result = postCompactRecovery(createInput());
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });

  describe('context recovery', () => {
    test('includes compaction number in output', () => {
      mockStateFile({
        compactionCount: 2,
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('Compaction #2'),
      );
    });

    test('prefers CC-provided compaction_count over file state', () => {
      mockStateFile({
        compactionCount: 2,
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput({ compaction_count: 5 }));
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('Compaction #5'),
      );
    });

    test('includes branch in output', () => {
      mockStateFile({
        preservedContext: { branch: 'feat/my-feature' },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('feat/my-feature'),
      );
    });

    test('includes recently edited files', () => {
      mockStateFile({
        preservedContext: { activeFiles: ['src/index.ts', 'package.json'] },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('src/index.ts'),
      );
    });

    test('truncates file list to 10', () => {
      const files = Array.from({ length: 15 }, (_, i) => `file${i}.ts`);
      mockStateFile({
        preservedContext: { activeFiles: files },
      });
      postCompactRecovery(createInput());
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).toContain('file0.ts');
      expect(ctx).toContain('file9.ts');
      expect(ctx).not.toContain('file10.ts');
    });

    test('includes active tasks', () => {
      mockStateFile({
        preservedContext: { activeTasks: ['Fix auth bug', 'Write tests'] },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('Fix auth bug'),
      );
    });

    test('includes recent decisions', () => {
      mockStateFile({
        preservedContext: { decisionLog: ['Use Postgres over MongoDB'] },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('Use Postgres over MongoDB'),
      );
    });

    test('includes compaction interval', () => {
      mockStateFile({
        avgCompactionIntervalMs: 300000,
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('5m'),
      );
    });

    test('includes memory snapshot', () => {
      mockStateFile({
        preservedContext: {
          memoryTierSnapshot: { localEntries: 42 },
        },
      });
      postCompactRecovery(createInput());
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('42'),
      );
    });
  });

  describe('token budget carry-forward (#1236)', () => {
    test('includes token budget when present', () => {
      mockStateFile({
        preservedContext: {
          tokenBudget: {
            estimatedUsed: 450,
            estimatedRemaining: 550,
            effortLevel: 'high',
          },
        },
      });
      postCompactRecovery(createInput());
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).toContain('450');
      expect(ctx).toContain('550');
      expect(ctx).toContain('high');
    });

    test('omits token budget when estimatedRemaining is 0', () => {
      mockStateFile({
        preservedContext: {
          branch: 'main',
          tokenBudget: {
            estimatedUsed: 1000,
            estimatedRemaining: 0,
            effortLevel: 'high',
          },
        },
      });
      postCompactRecovery(createInput());
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).not.toContain('Token budget');
    });

    test('handles missing estimatedUsed gracefully', () => {
      mockStateFile({
        preservedContext: {
          tokenBudget: {
            estimatedRemaining: 500,
            effortLevel: 'medium',
          },
        },
      });
      postCompactRecovery(createInput());
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).toContain('~0k used');
      expect(ctx).toContain('500');
    });

    test('defaults effort level to "default"', () => {
      mockStateFile({
        preservedContext: {
          tokenBudget: {
            estimatedUsed: 100,
            estimatedRemaining: 900,
          },
        },
      });
      postCompactRecovery(createInput());
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).toContain('effort: default');
    });
  });

  describe('circuit breaker warning', () => {
    test('warns at 3+ compactions', () => {
      mockStateFile({
        compactionCount: 3,
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput({ compaction_count: 3 }));
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('consider wrapping up'),
      );
    });

    test('no warning below 3 compactions', () => {
      mockStateFile({
        compactionCount: 2,
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput({ compaction_count: 2 }));
      const ctx = vi.mocked(outputWithContext).mock.calls[0][0];
      expect(ctx).not.toContain('consider wrapping up');
    });
  });

  describe('context_size_after', () => {
    test('includes context size when provided by CC', () => {
      mockStateFile({
        preservedContext: { branch: 'main' },
      });
      postCompactRecovery(createInput({ context_size_after: 150000 }));
      expect(outputWithContext).toHaveBeenCalledWith(
        expect.stringContaining('150k tokens'),
      );
    });
  });
});
